#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    static char P[1000005];
    while (T--) {
        scanf("%s", P);
        int len = strlen(P);
        int prev = 0;               // index of previous '#'
        int currJump = 1;
        int days = 0;
        for (int i = 1; i < len; ++i) {
            if (P[i] == '#') {
                int gap = i - prev;
                if (gap > currJump) {
                    ++days;
                    currJump = gap;
                }
                prev = i;
            }
        }
        printf("%d\n", days);
    }
    return 0;
}

